+  private buildFtsQuery(raw: string): string | null {
+    const tokens = raw.match(/[A-Za-z0-9_]+/g)?.map((t) => t.trim()).filter(Boolean) ?? [];
+    if (tokens.length === 0) return null;
+    const quoted = tokens.map((t) => `"${t.replaceAll("\"", "")}"`);
+    return quoted.join(" AND ");
+  }
+
+  private async searchKeyword(
+    query: string,
+    limit: number,
+  ): Promise<Array<MemorySearchResult & { id: string; textScore: number }>> {
+    if (!this.fts.enabled || !this.fts.available) return [];
+    if (limit <= 0) return [];
+    const ftsQuery = this.buildFtsQuery(query);
+    if (!ftsQuery) return [];
+    const sourceFilter = this.buildSourceFilter();
+    const rows = this.db
+      .prepare(
+        `SELECT id, path, source, start_line, end_line, text,\n` +
+          `       bm25(${FTS_TABLE}) AS rank\n` +
+          `  FROM ${FTS_TABLE}\n` +
+          ` WHERE ${FTS_TABLE} MATCH ? AND model = ?${sourceFilter.sql}\n` +
+          ` ORDER BY rank ASC\n` +
+          ` LIMIT ?`,
+      )
+      .all(ftsQuery, this.provider.model, ...sourceFilter.params, limit) as Array<{
+      id: string;
+      path: string;
+      source: MemorySource;
+      start_line: number;
+      end_line: number;
+      text: string;
+      rank: number;
+    }>;
+    return rows.map((row) => {
+      const rank = Number.isFinite(row.rank) ? Math.max(0, row.rank) : 999;
+      const textScore = 1 / (1 + rank);
+      return {
+        id: row.id,
+        path: row.path,
+        startLine: row.start_line,
+        endLine: row.end_line,
+        score: textScore,
+        textScore,
+        snippet: truncateUtf16Safe(row.text, SNIPPET_MAX_CHARS),
+        source: row.source,
+      };
+    });
+  }
+
+  private mergeHybridResults(params: {
+    vector: Array<MemorySearchResult & { id: string }>;
+    keyword: Array<MemorySearchResult & { id: string; textScore: number }>;
+    vectorWeight: number;
+    textWeight: number;
+  }): MemorySearchResult[] {
+    const byId = new Map<
+      string,
+      {
+        id: string;
+        path: string;
+        startLine: number;
+        endLine: number;
+        source: MemorySource;
+        snippet: string;
+        vectorScore: number;
+        textScore: number;
+      }
+    >();
+
+    for (const r of params.vector) {
+      byId.set(r.id, {
+        id: r.id,
+        path: r.path,
+        startLine: r.startLine,
+        endLine: r.endLine,
+        source: r.source,
+        snippet: r.snippet,
+        vectorScore: r.score,
+        textScore: 0,
+      });
+    }
+    for (const r of params.keyword) {
+      const existing = byId.get(r.id);
+      if (existing) {
+        existing.textScore = r.textScore;
+        if (r.snippet && r.snippet.length > 0) existing.snippet = r.snippet;
+      } else {
+        byId.set(r.id, {
+          id: r.id,
+          path: r.path,
+          startLine: r.startLine,
+          endLine: r.endLine,
+          source: r.source,
+          snippet: r.snippet,
+          vectorScore: 0,
+          textScore: r.textScore,
+        });
+      }
+    }
+
+    const merged = Array.from(byId.values()).map((entry) => {
+      const score = params.vectorWeight * entry.vectorScore + params.textWeight * entry.textScore;
+      return {
+        path: entry.path,
+        startLine: entry.startLine,
+        endLine: entry.endLine,
+        score,
+        snippet: entry.snippet,
+        source: entry.source,
+      } satisfies MemorySearchResult;
+    });
+    return merged.sort((a, b) => b.score - a.score);
+  }
